// Debounce function - delays execution until after delay has passed since last call
function debounce(func, delay) {
    let timeoutId;

    return function debounced(...args) {
        const context = this;

        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => {
            func.apply(context, args);
        }, delay);
    };
}

// Throttle function - limits execution to at most once per delay period
function throttle(func, delay) {
    let lastCallTime = 0;
    let timeoutId;

    return function throttled(...args) {
        const context = this;
        const now = Date.now();

        if (now - lastCallTime >= delay) {
            // Execute immediately if enough time has passed
            lastCallTime = now;
            func.apply(context, args);
        } else {
            // Schedule execution at the end of the current period
            clearTimeout(timeoutId);
            timeoutId = setTimeout(() => {
                lastCallTime = Date.now();
                func.apply(context, args);
            }, delay - (now - lastCallTime));
        }
    };
}

// Enhanced debounce with immediate option
function debounceAdvanced(func, delay, immediate = false) {
    let timeoutId;

    return function debouncedAdvanced(...args) {
        const context = this;
        const callNow = immediate && !timeoutId;

        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => {
            timeoutId = null;
            if (!immediate) func.apply(context, args);
        }, delay);

        if (callNow) func.apply(context, args);
    };
}

